public ListNode reverseList(ListNode head) {
    if (head == null) return null;

    Stack stack = new Stack<>();
    ListNode current = head;

    // Push all nodes onto stack
    while (current != null) {
        stack.push(current);
        current = current.next;
    }

    // Pop nodes and rebuild list
    ListNode newHead = stack.pop();
    current = newHead;

    while (!stack.isEmpty()) {
        current.next = stack.pop();
        current = current.next;
    }

    current.next = null;
    return newHead;
}

public ListNode reverseKGroup(ListNode head, int k) {
    if (head == null || k == 1) return head;

    ListNode dummy = new ListNode(0);
    dummy.next = head;
    ListNode prev = dummy;

    int count = 0;
    ListNode current = head;

    while (current != null) {
        count++;
        if (count % k == 0) {
            prev = reverse(prev, current.next);
            current = prev.next;
        } else {
            current = current.next;
        }
    }

    return dummy.next;
}

private ListNode reverse(ListNode start, ListNode end) {
    ListNode prev = start;
    ListNode current = start.next;
    ListNode first = current;

    while (current != end) {
        ListNode next = current.next;
        current.next = prev;
        prev = current;
        current = next;
    }

    start.next = prev;
    first.next = current;

    return first;
}

public ListNode reverseList(ListNode head) {
    // Handle null and single node cases
    if (head == null || head.next == null) {
        return head;
    }

    ListNode prev = null;
    ListNode current = head;

    while (current != null) {
        // Store next node before changing links
        ListNode nextTemp = current.next;

        // Reverse the link
        current.next = prev;

        // Move pointers forward
        prev = current;
        current = nextTemp;
    }

    return prev;
}

